class Solution:
    def zigzagLevelOrder(self, root):
        levels = []
        def walk(node, depth):
            if node is None:
                return
            if depth == len(levels):
                levels.append([])
            levels[depth].append(node.val)
            walk(node.left, depth + 1)
            walk(node.right, depth + 1)
        walk(root, 0)
        for d in range(len(levels)):
            if d % 2 == 1:
                levels[d] = levels[d][::-1]
        return levels

