var zigzagLevelOrder = function(root) {
    if (!root) return [];
    const res = [];
    let level = [root];
    let leftToRight = true;
    while (level.length) {
        const vals = [];
        const next = [];
        for (const node of level) {
            vals.push(node.val);
            if (node.left) next.push(node.left);
            if (node.right) next.push(node.right);
        }
        if (!leftToRight) vals.reverse();
        res.push(vals);
        level = next;
        leftToRight = !leftToRight;
    }
    return res;
};
